raw_log = _items[0]["json"].get("data", "")

# --- Strip ANSI escape sequences without regex ---
clean = ""
i = 0
while i < len(raw_log):
    if raw_log[i] == "\x1b":
        # Skip ESC[ ... <letter> sequences (CSI)
        if i + 1 < len(raw_log) and raw_log[i + 1] == "[":
            i += 2
            while i < len(raw_log) and not raw_log[i].isalpha():
                i += 1
            i += 1  # skip the final letter
            continue
        # Skip ESC] ... ESC\ sequences (OSC, used by GitLab hyperlinks)
        elif i + 1 < len(raw_log) and raw_log[i + 1] == "]":
            i += 2
            while i < len(raw_log):
                if raw_log[i] == "\x1b" and i + 1 < len(raw_log) and raw_log[i + 1] == "\\":
                    i += 2
                    break
                i += 1
            continue
        else:
            i += 1
            continue
    clean += raw_log[i]
    i += 1

# --- Filter out section markers and empty lines ---
lines = []
for line in clean.splitlines():
    stripped = line.strip()
    if not stripped:
        continue
    if stripped.startswith("section_start:") or stripped.startswith("section_end:"):
        continue
    lines.append(line)

# --- Keep last 50 lines ---
max_lines = 50
total = len(lines)
if total > max_lines:
    trimmed = lines[-max_lines:]
    header = "[... truncated " + str(total - max_lines) + " lines, showing last " + str(max_lines) + " ...]\n"
else:
    trimmed = lines
    header = ""

return [{
    "job_log": header + "\n".join(trimmed),
}]

result = {}

for item in _items:
    data = item["json"]

    # Item with job_log
    if "job_log" in data:
        result["job_log"] = data["job_log"]
        result["job_log_total_lines"] = data.get("job_log_total_lines", 0)

    # Item with pipeline context and failed job info
    if "pipeline" in data:
        result["pipeline"] = data["pipeline"]
        result["failed_job"] = data["failed_job"]

    # Item with CI config (raw YAML as string)
    if "data" in data and "pipeline" not in data and "job_log" not in data:
        result["ci_config"] = data["data"]

    # Item with commit diff (array of changed files)
    if "diff" in data or (isinstance(data, list) and len(data) > 0 and "diff" in data[0]):
        result["commit_diff"] = data

return [result]
